const express = require('express');
const mysql = require('mysql');
const app = express();

// MySQL Connection configuration
var pool  = mysql.createPool({
  connectionLimit : 10,
  host            : 'localhost',
  user            : 'root',
  password        : 'password',
  database        : 'ProductDB'
});

app.get('/search/:name', (req, res) => {
    pool.query('SELECT * FROM Products WHERE name LIKE "%' + req.params.name + '%" ', function(error, results, fields) {
      if (error) throw error; // If there is an error in the SQL query process we will get that data back
      
      res.send({"results": JSON.parse(JSON.stringify(results))}); 
    });  
});

app.listen(3000, () => console.log('Listening on port 3000...'));